class Solution:
    def largestPerimeter(self, nums):
        srt = sorted(nums)
        n = len(srt)
        prefix = [0] * (n + 1)
        for i, v in enumerate(srt):
            prefix[i + 1] = prefix[i] + v
        best = -1
        for i in range(2, n):
            if prefix[i] > srt[i]:
                perimeter = prefix[i + 1]
                if perimeter > best:
                    best = perimeter
        return best

