class Solution:
    def largestPerimeter(self, nums):
        srt = sorted(nums)
        n = len(srt)
        prefix = [0] * (n + 1)
        for i, v in enumerate(srt):
            prefix[i + 1] = prefix[i] + v
        for i in range(n - 1, 1, -1):
            if prefix[i] > srt[i]:
                return prefix[i + 1]
        return -1

