var largestPerimeter = function(nums) {
    const srt = nums.slice().sort((a, b) => a - b);
    const n = srt.length;
    const prefix = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) prefix[i + 1] = prefix[i] + srt[i];
    for (let i = n - 1; i >= 2; i--) {
        if (prefix[i] > srt[i]) return prefix[i + 1];
    }
    return -1;
};
